// Game configuration
const FLOWERS = ['🌻', '🌷', '🌸', '🌺', '🌼', '💐', '🌻', '🌷', '🌸', '🌺', '🌼', '💐'];

// Language translations
const translations = {
    en: {
            title: "🌸 PIXEL FLORAL MEMORY 🌸",
                    subtitle: "match the flowers !",
                            movesLabel: "MOVES",
                                    timeLabel: "TIME",
                                            bestLabel: "BEST",
                                                    resetBtn: "🌱 NEW GAME 🌱",
                                                            winMessage: "🎉 VICTORY! 🎉",
                                                                    winRecord: "🏆 NEW RECORD! 🏆",
                                                                            winText: "You won in {moves} moves and {time}s!",
                                                                                    langBtn: "中文"
                                                                                        },
                                                                                            zh: {
                                                                                                    title: "🌸 像素花之记忆 🌸",
                                                                                                            subtitle: "找到配对的花朵 ！",
                                                                                                                    movesLabel: "步数",
                                                                                                                            timeLabel: "时间",
                                                                                                                                    bestLabel: "最佳",
                                                                                                                                            resetBtn: "🌱 新游戏 🌱",
                                                                                                                                                    winMessage: "🎉 胜利啦！ 🎉",
                                                                                                                                                            winRecord: "🏆 新纪录！ 🏆",
                                                                                                                                                                    winText: "你用 {moves} 步和 {time} 秒赢了！",
                                                                                                                                                                            langBtn: "EN"
                                                                                                                                                                                }
                                                                                                                                                                                };

                                                                                                                                                                                let currentLang = 'en';
                                                                                                                                                                                let cards = [];
                                                                                                                                                                                let flippedCards = [];
                                                                                                                                                                                let matchedPairs = 0;
                                                                                                                                                                                let moves = 0;
                                                                                                                                                                                let timer = 0;
                                                                                                                                                                                let timerInterval = null;
                                                                                                                                                                                let gameStarted = false;
                                                                                                                                                                                let lockBoard = false;

                                                                                                                                                                                // DOM elements
                                                                                                                                                                                const boardElement = document.getElementById('board');
                                                                                                                                                                                const movesElement = document.getElementById('moves');
                                                                                                                                                                                const timerElement = document.getElementById('timer');
                                                                                                                                                                                const bestScoreElement = document.getElementById('bestScore');
                                                                                                                                                                                const resetBtn = document.getElementById('resetBtn');
                                                                                                                                                                                const messageElement = document.getElementById('message');
                                                                                                                                                                                const langSwitch = document.getElementById('langSwitch');
                                                                                                                                                                                const langText = document.getElementById('langText');

                                                                                                                                                                                // Load best score from localStorage
                                                                                                                                                                                let bestScore = localStorage.getItem('pixelBestScore') || Infinity;

                                                                                                                                                                                function updateUILanguage() {
                                                                                                                                                                                    const t = translations[currentLang];
                                                                                                                                                                                        document.getElementById('gameTitle').textContent = t.title;
                                                                                                                                                                                            document.getElementById('gameSubtitle').textContent = t.subtitle;
                                                                                                                                                                                                document.getElementById('movesLabel').textContent = t.movesLabel;
                                                                                                                                                                                                    document.getElementById('timeLabel').textContent = t.timeLabel;
                                                                                                                                                                                                        document.getElementById('bestLabel').textContent = t.bestLabel;
                                                                                                                                                                                                            document.getElementById('resetText').textContent = t.resetBtn;
                                                                                                                                                                                                                langText.textContent = t.langBtn;
                                                                                                                                                                                                                    
                                                                                                                                                                                                                        // Update message if visible
                                                                                                                                                                                                                            if (messageElement.classList.contains('show')) {
                                                                                                                                                                                                                                    const currentMessage = messageElement.textContent;
                                                                                                                                                                                                                                            if (currentMessage.includes('Victory') || currentMessage.includes('胜利')) {
                                                                                                                                                                                                                                                        // Re-show victory message with new language
                                                                                                                                                                                                                                                                    showVictoryMessage();
                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                function showVictoryMessage() {
                                                                                                                                                                                                                                                                                    const t = translations[currentLang];
                                                                                                                                                                                                                                                                                        let message = `${t.winMessage}\n${t.winText.replace('{moves}', moves).replace('{time}', timer)}`;
                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                if (moves < bestScore) {
                                                                                                                                                                                                                                                                                                        message += `\n${t.winRecord}`;
                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                    messageElement.textContent = message;
                                                                                                                                                                                                                                                                                                                        messageElement.classList.add('show');
                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                        function shuffleArray(array) {
                                                                                                                                                                                                                                                                                                                            for (let i = array.length - 1; i > 0; i--) {
                                                                                                                                                                                                                                                                                                                                    const j = Math.floor(Math.random() * (i + 1));
                                                                                                                                                                                                                                                                                                                                            [array[i], array[j]] = [array[j], array[i]];
                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                    return array;
                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                    function updateBestScoreDisplay() {
                                                                                                                                                                                                                                                                                                                                                        if (bestScore === Infinity) {
                                                                                                                                                                                                                                                                                                                                                                bestScoreElement.textContent = '-';
                                                                                                                                                                                                                                                                                                                                                                    } else {
                                                                                                                                                                                                                                                                                                                                                                            bestScoreElement.textContent = bestScore;
                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                function initGame() {
                                                                                                                                                                                                                                                                                                                                                                                    const shuffledFlowers = shuffleArray([...FLOWERS]);
                                                                                                                                                                                                                                                                                                                                                                                        cards = shuffledFlowers.map((flower, index) => ({
                                                                                                                                                                                                                                                                                                                                                                                                id: index,
                                                                                                                                                                                                                                                                                                                                                                                                        flower: flower,
                                                                                                                                                                                                                                                                                                                                                                                                                isFlipped: false,
                                                                                                                                                                                                                                                                                                                                                                                                                        isMatched: false
                                                                                                                                                                                                                                                                                                                                                                                                                            }));
                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                    flippedCards = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                        matchedPairs = 0;
                                                                                                                                                                                                                                                                                                                                                                                                                                            moves = 0;
                                                                                                                                                                                                                                                                                                                                                                                                                                                updateMovesDisplay();
                                                                                                                                                                                                                                                                                                                                                                                                                                                    gameStarted = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                        lockBoard = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (timerInterval) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        clearInterval(timerInterval);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                timerInterval = null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        timer = 0;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            timerElement.textContent = '0s';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                messageElement.classList.remove('show');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        renderBoard();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        function renderBoard() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            boardElement.innerHTML = '';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cards.forEach(card => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const cardElement = document.createElement('div');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cardElement.className = 'card';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (card.isFlipped || card.isMatched) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cardElement.classList.add('flipped');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cardElement.textContent = card.flower;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cardElement.textContent = '?';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (card.isMatched) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cardElement.classList.add('matched');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cardElement.addEventListener('click', () => onCardClick(card.id));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        boardElement.appendChild(cardElement);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            function startTimer() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (timerInterval) clearInterval(timerInterval);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    timerInterval = setInterval(() => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            timer++;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    timerElement.textContent = `${timer}s`;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }, 1000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        function updateMovesDisplay() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            movesElement.textContent = moves;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            function endGame() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (timerInterval) clearInterval(timerInterval);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (moves < bestScore) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                bestScore = moves;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        localStorage.setItem('pixelBestScore', bestScore);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                updateBestScoreDisplay();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            showVictoryMessage();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                gameStarted = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                function checkMatch() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const [card1, card2] = flippedCards;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (card1.flower === card2.flower) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Match found
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            card1.isMatched = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    card2.isMatched = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            matchedPairs++;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    flippedCards = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (matchedPairs === cards.length / 2) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                endGame();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    renderBoard();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        lockBoard = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                setTimeout(() => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            card1.isFlipped = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        card2.isFlipped = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    flippedCards = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                renderBoard();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            lockBoard = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }, 500);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        function onCardClick(cardId) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (lockBoard) return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const card = cards[cardId];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (card.isMatched || card.isFlipped) return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (!gameStarted) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        gameStarted = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                startTimer();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            card.isFlipped = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                flippedCards.push(card);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    renderBoard();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (flippedCards.length === 2) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    moves++;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            updateMovesDisplay();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    checkMatch();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Event listeners
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        resetBtn.addEventListener('click', () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (timerInterval) clearInterval(timerInterval);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                initGame();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                langSwitch.addEventListener('click', () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    currentLang = currentLang === 'en' ? 'zh' : 'en';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        updateUILanguage();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Initialize game
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        updateBestScoreDisplay();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        initGame();